#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

// Fast I/O
void fast_io() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
}

void solve() {
    int n, m;
    if (!(cin >> n >> m)) return;

    // Temporary adjacency list to filter out duplicates and self-loops
    vector<vector<int>> temp_adj(n);
    for (int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        u--; v--; // Convert to 0-indexed
        if (u == v) continue; // Skip self-loops
        temp_adj[u].push_back(v);
        temp_adj[v].push_back(u);
    }

    // Sort and remove duplicate neighbors for each node
    int unique_edges = 0;
    for (int i = 0; i < n; i++) {
        sort(temp_adj[i].begin(), temp_adj[i].end());
        temp_adj[i].erase(unique(temp_adj[i].begin(), temp_adj[i].end()), temp_adj[i].end());
        unique_edges += temp_adj[i].size();
    }

    // Rebuild the optimized flat adjacency list
    vector<int> head(n, -1);
    vector<int> to(unique_edges);
    vector<int> nxt(unique_edges);
    int edge_count = 0;

    for (int u = 0; u < n; u++) {
        for (int v : temp_adj[u]) {
            to[edge_count] = v;
            nxt[edge_count] = head[u];
            head[u] = edge_count++;
        }
    }

    // Doubly linked list for unvisited nodes
    // head of the list is index n, tail is index n + 1
    vector<int> prev_node(n + 2);
    vector<int> next_node(n + 2);

    next_node[n] = 0;
    prev_node[0] = n;
    for (int i = 0; i < n - 1; i++) {
        next_node[i] = i + 1;
        prev_node[i + 1] = i;
    }
    next_node[n - 1] = n + 1;
    prev_node[n + 1] = n - 1;

    vector<int> color(n, -1);
    vector<int> marker(n, -1);
    vector<int> queue(n);

    for (int i = 0; i < n; i++) {
        if (color[i] != -1) continue;

        // Start BFS: remove node 'i' from unvisited list
        next_node[prev_node[i]] = next_node[i];
        prev_node[next_node[i]] = prev_node[i];
        color[i] = 0;

        int q_head = 0, q_tail = 0;
        queue[q_tail++] = i;

        while (q_head < q_tail) {
            int u = queue[q_head++];
            int curr_color = color[u];
            int next_color = 1 - curr_color;

            // Mark all neighbors of u in G
            for (int e = head[u]; e != -1; e = nxt[e]) {
                marker[to[e]] = u;
            }

            // Traverse unvisited nodes in complement graph
            int curr = next_node[n];
            while (curr != n + 1) {
                int nxt_curr = next_node[curr];
                if (marker[curr] != u) {
                    // curr is a neighbor of u in complement graph
                    color[curr] = next_color;

                    // remove node 'curr' from unvisited list
                    next_node[prev_node[curr]] = next_node[curr];
                    prev_node[next_node[curr]] = prev_node[curr];

                    queue[q_tail++] = curr;
                }
                curr = nxt_curr;
            }
        }
    }

    // Count colors
    int count0 = 0, count1 = 0;
    for (int i = 0; i < n; i++) {
        if (color[i] == 0) count0++;
        else if (color[i] == 1) count1++;
    }

    // Check if the colored parts are indeed cliques in G
    vector<int> deg_same_color(n, 0);
    for (int u = 0; u < n; u++) {
        for (int e = head[u]; e != -1; e = nxt[e]) {
            int v = to[e];
            if (color[u] == color[v]) {
                deg_same_color[u]++;
            }
        }
    }

    for (int u = 0; u < n; u++) {
        if (color[u] == 0) {
            if (deg_same_color[u] != count0 - 1) {
                cout << "NO\n";
                return;
            }
        } else if (color[u] == 1) {
            if (deg_same_color[u] != count1 - 1) {
                cout << "NO\n";
                return;
            }
        }
    }

    cout << "YES\n";
}

int main() {
    fast_io();
    int t;
    if (cin >> t) {
        while (t--) {
            solve();
        }
    }
    return 0;
}

