#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXN 10005
#define MAXM 2000005

typedef struct {
    int u, v;
} Edge;

int compare_edges(const void* a, const void* b) {
    Edge* ea = (Edge*)a;
    Edge* eb = (Edge*)b;
    if (ea->u != eb->u) return ea->u - eb->u;
    return ea->v - eb->v;
}

Edge edges[MAXM];
int head[MAXN];
int to_node[MAXM];
int next_edge[MAXM];

int prev_node[MAXN + 2];
int next_node[MAXN + 2];
int color[MAXN];
int marker[MAXN];
int queue[MAXN];
int deg_same_color[MAXN];

void remove_node(int i) {
    next_node[prev_node[i]] = next_node[i];
    prev_node[next_node[i]] = prev_node[i];
}

void solve() {
    int n, m;
    if (scanf("%d %d", &n, &m) != 2) return;

    int edge_count = 0;
    for (int i = 0; i < m; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--; v--;
        if (u == v) continue; // Skip self-loops

        edges[edge_count].u = u;
        edges[edge_count].v = v;
        edge_count++;

        edges[edge_count].u = v;
        edges[edge_count].v = u;
        edge_count++;
    }

    // Sort edges to group neighbors contiguously
    qsort(edges, edge_count, sizeof(Edge), compare_edges);

    // De-duplicate and build flat adjacency list
    memset(head, -1, sizeof(int) * n);
    int unique_edge_count = 0;
    for (int i = 0; i < edge_count; i++) {
        if (i > 0 && edges[i].u == edges[i - 1].u && edges[i].v == edges[i - 1].v) {
            continue; // Skip duplicate edges
        }
        int u = edges[i].u;
        int v = edges[i].v;
        to_node[unique_edge_count] = v;
        next_edge[unique_edge_count] = head[u];
        head[u] = unique_edge_count++;
    }

    // Initialize doubly linked list
    next_node[n] = 0;
    prev_node[0] = n;
    for (int i = 0; i < n - 1; i++) {
        next_node[i] = i + 1;
        prev_node[i + 1] = i;
    }
    next_node[n - 1] = n + 1;
    prev_node[n + 1] = n - 1;

    memset(color, -1, sizeof(int) * n);
    memset(marker, -1, sizeof(int) * n);

    for (int i = 0; i < n; i++) {
        if (color[i] != -1) continue;

        remove_node(i);
        color[i] = 0;

        int q_head = 0, q_tail = 0;
        queue[q_tail++] = i;

        while (q_head < q_tail) {
            int u = queue[q_head++];
            int curr_color = color[u];
            int next_color = 1 - curr_color;

            for (int e = head[u]; e != -1; e = next_edge[e]) {
                marker[to_node[e]] = u;
            }

            int curr = next_node[n];
            while (curr != n + 1) {
                int nxt_curr = next_node[curr];
                if (marker[curr] != u) {
                    color[curr] = next_color;
                    remove_node(curr);
                    queue[q_tail++] = curr;
                }
                curr = nxt_curr;
            }
        }
    }

    int count0 = 0, count1 = 0;
    for (int i = 0; i < n; i++) {
        if (color[i] == 0) count0++;
        else if (color[i] == 1) count1++;
    }

    memset(deg_same_color, 0, sizeof(int) * n);
    for (int u = 0; u < n; u++) {
        for (int e = head[u]; e != -1; e = next_edge[e]) {
            int v = to_node[e];
            if (color[u] == color[v]) {
                deg_same_color[u]++;
            }
        }
    }

    for (int u = 0; u < n; u++) {
        if (color[u] == 0) {
            if (deg_same_color[u] != count0 - 1) {
                printf("NO\n");
                return;
            }
        } else if (color[u] == 1) {
            if (deg_same_color[u] != count1 - 1) {
                printf("NO\n");
                return;
            }
        }
    }
    printf("YES\n");
}

int main() {
    int t;
    if (scanf("%d", &t) == 1) {
        while (t--) {
            solve();
        }
    }
    return 0;
}

