import java.io.InputStream;
import java.io.IOException;
import java.util.Arrays;

public class Main {
    // Custom Byte-Level Fast Scanner (no string allocations)
    static class FastScanner {
        private final InputStream in = System.in;
        private final byte[] buffer = new byte[32768];
        private int ptr = 0;
        private int buflen = 0;

        private boolean hasNextByte() {
            if (ptr < buflen) return true;
            ptr = 0;
            try {
                buflen = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace();
            }
            return buflen > 0;
        }

        private int readByte() {
            if (hasNextByte()) return buffer[ptr++];
            return -1;
        }

        public int nextInt() {
            int b = readByte();
            while (b != -1 && b <= 32) {
                b = readByte();
            }
            if (b == -1) return -1;
            int n = 0;
            while (b > 32) {
                if (b >= '0' && b <= '9') {
                    n = n * 10 + (b - '0');
                }
                b = readByte();
            }
            return n;
        }
    }

    public static void main(String[] args) {
        FastScanner sc = new FastScanner();
        int t = sc.nextInt();
        if (t == -1) return;

        StringBuilder sb = new StringBuilder();

        // Statically sized arrays to prevent reallocation overhead
        int[] edgesPacked = new int[1000005];
        int[] head = new int[1005];
        int[] to = new int[2000005];
        int[] nxt = new int[2000005];
        int[] prevNode = new int[1005];
        int[] nextNode = new int[1005];
        int[] color = new int[1005];
        int[] marker = new int[1005];
        int[] queue = new int[1005];
        int[] degSameColor = new int[1005];

        while (t-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();

            int packedCount = 0;
            for (int i = 0; i < m; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                if (u == v) continue; // Skip self-loops
                if (u > v) {
                    int temp = u; u = v; v = temp;
                }
                edgesPacked[packedCount++] = (u << 16) | v;
            }

            // Global primitive sort (very fast)
            Arrays.sort(edgesPacked, 0, packedCount);

            Arrays.fill(head, 0, n, -1);
            int edgeCount = 0;

            for (int i = 0; i < packedCount; i++) {
                if (i > 0 && edgesPacked[i] == edgesPacked[i - 1]) {
                    continue; // Skip duplicate edges
                }
                int u = edgesPacked[i] >> 16;
                int v = edgesPacked[i] & 0xFFFF;

                // Add u -> v
                to[edgeCount] = v;
                nxt[edgeCount] = head[u];
                head[u] = edgeCount++;

                // Add v -> u
                to[edgeCount] = u;
                nxt[edgeCount] = head[v];
                head[v] = edgeCount++;
            }

            // Doubly linked list
            nextNode[n] = 0;
            prevNode[0] = n;
            for (int i = 0; i < n - 1; i++) {
                nextNode[i] = i + 1;
                prevNode[i + 1] = i;
            }
            nextNode[n - 1] = n + 1;
            prevNode[n + 1] = n - 1;

            Arrays.fill(color, 0, n, -1);
            Arrays.fill(marker, 0, n, -1);

            for (int i = 0; i < n; i++) {
                if (color[i] != -1) continue;

                // remove_node(i)
                nextNode[prevNode[i]] = nextNode[i];
                prevNode[nextNode[i]] = prevNode[i];
                color[i] = 0;

                int qHead = 0, qTail = 0;
                queue[qTail++] = i;

                while (qHead < qTail) {
                    int u = queue[qHead++];
                    int currColor = color[u];
                    int nextColor = 1 - currColor;

                    for (int e = head[u]; e != -1; e = nxt[e]) {
                        marker[to[e]] = u;
                    }

                    int curr = nextNode[n];
                    while (curr != n + 1) {
                        int nxtCurr = nextNode[curr];
                        if (marker[curr] != u) {
                            color[curr] = nextColor;
                            // remove_node(curr)
                            nextNode[prevNode[curr]] = nextNode[curr];
                            prevNode[nextNode[curr]] = prevNode[curr];
                            queue[qTail++] = curr;
                        }
                        curr = nxtCurr;
                    }
                }
            }

            int count0 = 0, count1 = 0;
            for (int i = 0; i < n; i++) {
                if (color[i] == 0) count0++;
                else if (color[i] == 1) count1++;
            }

            Arrays.fill(degSameColor, 0, n, 0);
            for (int u = 0; u < n; u++) {
                for (int e = head[u]; e != -1; e = nxt[e]) {
                    int v = to[e];
                    if (color[u] == color[v]) {
                        degSameColor[u]++;
                    }
                }
            }

            boolean possible = true;
            for (int u = 0; u < n; u++) {
                if (color[u] == 0) {
                    if (degSameColor[u] != count0 - 1) {
                        possible = false;
                        break;
                    }
                } else if (color[u] == 1) {
                    if (degSameColor[u] != count1 - 1) {
                        possible = false;
                        break;
                    }
                }
            }
            sb.append(possible ? "YES\n" : "NO\n");
        }
        System.out.print(sb);
    }
}

