function solve() {
    const buf = fs.readFileSync(0);
    let pos = 0;

    // Custom Byte Scanner
    function nextInt() {
        while (pos < buf.length && buf[pos] <= 32) {
            pos++;
        }
        if (pos >= buf.length) return -1;
        let res = 0;
        while (pos < buf.length && buf[pos] > 32) {
            res = res * 10 + (buf[pos] - 48);
            pos++;
        }
        return res;
    }

    const t = nextInt();
    if (t === -1) return;

    // Statically sized TypedArrays for performance
    const edgesPacked = new Int32Array(1000005);
    const head = new Int32Array(1005);
    const to = new Int32Array(2000005);
    const nxt = new Int32Array(2000005);
    const prevNode = new Int32Array(1005);
    const nextNode = new Int32Array(1005);
    const color = new Int8Array(1005);
    const marker = new Int32Array(1005);
    const queue = new Int32Array(1005);
    const degSameColor = new Int32Array(1005);

    const out = [];

    for (let tc = 0; tc < t; tc++) {
        const n = nextInt();
        const m = nextInt();
        if (n === -1) break;

        let packedCount = 0;
        for (let i = 0; i < m; i++) {
            let u = nextInt() - 1;
            let v = nextInt() - 1;
            if (u === v) continue;
            if (u > v) {
                const tmp = u; u = v; v = tmp;
            }
            edgesPacked[packedCount++] = (u << 16) | v;
        }

        // Fast sort of a sub-segment of TypedArray
        const subArray = edgesPacked.subarray(0, packedCount);
        subArray.sort();

        head.fill(-1, 0, n);
        let edgeCount = 0;

        for (let i = 0; i < packedCount; i++) {
            if (i > 0 && subArray[i] === subArray[i - 1]) {
                continue;
            }
            const u = subArray[i] >> 16;
            const v = subArray[i] & 0xFFFF;

            to[edgeCount] = v;
            nxt[edgeCount] = head[u];
            head[u] = edgeCount++;

            to[edgeCount] = u;
            nxt[edgeCount] = head[v];
            head[v] = edgeCount++;
        }

        nextNode[n] = 0;
        prevNode[0] = n;
        for (let i = 0; i < n - 1; i++) {
            nextNode[i] = i + 1;
            prevNode[i + 1] = i;
        }
        nextNode[n - 1] = n + 1;
        prevNode[n + 1] = n - 1;

        color.fill(-1, 0, n);
        marker.fill(-1, 0, n);

        for (let i = 0; i < n; i++) {
            if (color[i] !== -1) continue;

            // removeNode(i) inline
            nextNode[prevNode[i]] = nextNode[i];
            prevNode[nextNode[i]] = prevNode[i];
            color[i] = 0;

            let qHead = 0, qTail = 0;
            queue[qTail++] = i;

            while (qHead < qTail) {
                const u = queue[qHead++];
                const currColor = color[u];
                const nextColor = 1 - currColor;

                let e = head[u];
                while (e !== -1) {
                    marker[to[e]] = u;
                    e = nxt[e];
                }

                let curr = nextNode[n];
                while (curr !== n + 1) {
                    const nxtCurr = nextNode[curr];
                    if (marker[curr] !== u) {
                        color[curr] = nextColor;
                        // removeNode(curr) inline
                        nextNode[prevNode[curr]] = nextNode[curr];
                        prevNode[nextNode[curr]] = prevNode[curr];
                        queue[qTail++] = curr;
                    }
                    curr = nxtCurr;
                }
            }
        }

        let count0 = 0, count1 = 0;
        for (let i = 0; i < n; i++) {
            if (color[i] === 0) count0++;
            else if (color[i] === 1) count1++;
        }

        degSameColor.fill(0, 0, n);
        for (let u = 0; u < n; u++) {
            let e = head[u];
            while (e !== -1) {
                const v = to[e];
                if (color[u] === color[v]) {
                    degSameColor[u]++;
                }
                e = nxt[e];
            }
        }

        let possible = true;
        for (let u = 0; u < n; u++) {
            if (color[u] === 0) {
                if (degSameColor[u] !== count0 - 1) {
                    possible = false;
                    break;
                }
            } else if (color[u] === 1) {
                if (degSameColor[u] !== count1 - 1) {
                    possible = false;
                    break;
                }
            }
        }
        out.push(possible ? "YES" : "NO");
    }
    console.log(out.join('\n'));
